import { describe, it, afterEach } from "node:test";
import assert from "node:assert/strict";

import { requireEvaluateAuth } from "../src/routes/evaluate.js";

function mockRes() {
  return {
    statusCode: null,
    body: null,
    status(code) { this.statusCode = code; return this; },
    json(payload) { this.body = payload; return this; },
  };
}

function run(headers) {
  const res = mockRes();
  let nextCalled = false;
  requireEvaluateAuth({ headers }, res, () => { nextCalled = true; });
  return { res, nextCalled };
}

const original = process.env.ENGINE_EVALUATE_AUTH_TOKEN;
afterEach(() => {
  if (original === undefined) delete process.env.ENGINE_EVALUATE_AUTH_TOKEN;
  else process.env.ENGINE_EVALUATE_AUTH_TOKEN = original;
});

describe("requireEvaluateAuth", () => {
  it("is open when no token is configured", () => {
    delete process.env.ENGINE_EVALUATE_AUTH_TOKEN;
    const { res, nextCalled } = run({});
    assert.equal(nextCalled, true);
    assert.equal(res.statusCode, null);
  });

  it("rejects a missing Authorization header when configured", () => {
    process.env.ENGINE_EVALUATE_AUTH_TOKEN = "engine-secret";
    const { res, nextCalled } = run({});
    assert.equal(nextCalled, false);
    assert.equal(res.statusCode, 401);
    assert.equal(res.body.error, "unauthorized");
  });

  it("rejects a wrong token", () => {
    process.env.ENGINE_EVALUATE_AUTH_TOKEN = "engine-secret";
    const { res, nextCalled } = run({ authorization: "Bearer nope" });
    assert.equal(nextCalled, false);
    assert.equal(res.statusCode, 401);
  });

  it("accepts the matching token", () => {
    process.env.ENGINE_EVALUATE_AUTH_TOKEN = "engine-secret";
    const { res, nextCalled } = run({ authorization: "Bearer engine-secret" });
    assert.equal(nextCalled, true);
    assert.equal(res.statusCode, null);
  });
});
